import React from "react";
import { Paper, Typography, Grid, IconButton } from "@mui/material";
import { ThemeProvider, createTheme } from "@mui/material";
import {useState, useEffect} from "react";
import { ReactComponent as Logo } from './Group 726.svg';

const SensorReadings = () => {
  const theme = createTheme({
    typography: {
      fontFamily: ["Inter"],
    },
  });
  const [field, setfield] = useState([]);


  useEffect(() => {
    const fetchData = async () => {
      const response = await fetch("https://api.thingspeak.com/channels/1682332/feeds.json?api_key=JJN2ESGESP51H4JP&results=2");
      const data = await response.json();
      const sensorData = data.feeds.map((sensor)=>{
        return {
          id : sensor.entry_id,
          turbidity : sensor.field1,
          pH : sensor.field2,
          waterContent : sensor.field3,
          bill : sensor.field4,
        }
      })
      setfield(sensorData[sensorData.length - 1]);
      console.log(sensorData[sensorData.length - 1])
    }
    fetchData();
    const interval=setInterval(()=>{
      fetchData()
     },16000)
     return()=>clearInterval(interval)
  }, []);




  return (
    <ThemeProvider theme={theme}>
      <Grid container spacing={0}>
        {/* // Water level */}
        <Grid
          item
          md={12}
          xs={12}
          sx={{
            pl: { md: 6, xs: 6 },
            pt: { md: 10, xs: 3 },
            pb: { md: 2, xs: 3 },
            pr: { xs: 3 },
            textAlign: "center",
          }}
        >
          <Paper
            sx={{
              p: 4,
              fontSize: { md: "1.2rem", xs: "0.8 rem" },
              borderRadius: "20px",
            }}
            elevation={12}
          >

            <Typography
              variant="h5"
              fontWeight={600}
              gutterBottom
              sx={{ textAlign: { md: "center", sx: "center" } }}
            >
              Trusted by Over 40+ Businesses
            </Typography>
            <Logo />
          </Paper>
        </Grid>


      </Grid>
    </ThemeProvider>
  );
};

export default SensorReadings;
